package com.spendwise.prototype.data; import androidx.room.*; import kotlinx.coroutines.flow.Flow; @Dao interface UserDao{ @Insert suspend fun insert(u:User); @Query("SELECT * FROM users WHERE username=:u AND password=:p LIMIT 1") suspend fun login(u:String,p:String):User? } @Dao interface CategoryDao{ @Insert suspend fun insert(c:Category); @Query("SELECT * FROM categories") fun getAll():Flow<List<Category>> } @Dao interface ExpenseDao{ @Insert suspend fun insert(e:Expense); @Query("SELECT * FROM expenses WHERE dateMillis BETWEEN :s AND :e ORDER BY dateMillis DESC") fun between(s:Long,e:Long):Flow<List<Expense>>; @Query("SELECT categoryId, SUM(amount) as total FROM expenses WHERE dateMillis BETWEEN :s AND :e GROUP BY categoryId") fun totalsPerCategory(s:Long,e:Long):Flow<List<CategoryTotal>> } data class CategoryTotal(val categoryId:Long,val total:Double); @Dao interface GoalDao{ @Insert(onConflict=OnConflictStrategy.REPLACE) suspend fun set(g:BudgetGoal); @Query("SELECT * FROM goals WHERE categoryId=:id") suspend fun get(id:Long):BudgetGoal? }